import{_ as t,g as a,c as l,B as o}from"./chunks/framework.UqVR3kzU.js";const c=JSON.parse('{"title":"🚪 第一部分：入门前置","description":"","frontmatter":{},"headers":[],"relativePath":"part1.md","filePath":"part1.md","lastUpdated":null}'),n={name:"part1.md"};function i(e,r,s,g,h,u){return a(),l("div",null,[...r[0]||(r[0]=[o('<h1 id="🚪-第一部分-入门前置" tabindex="-1">🚪 第一部分：入门前置 <a class="header-anchor" href="#🚪-第一部分-入门前置" aria-label="Permalink to &quot;🚪 第一部分：入门前置&quot;">​</a></h1><h2 id="1.软硬件工具箱" tabindex="-1">1. 软硬件工具箱 <a class="header-anchor" href="#1.软硬件工具箱" aria-label="Permalink to &quot;1. 软硬件工具箱{#1.软硬件工具箱}&quot;">​</a></h2><h3 id="_1-1-设计工具清单" tabindex="-1">1.1 设计工具清单 <a class="header-anchor" href="#_1-1-设计工具清单" aria-label="Permalink to &quot;1.1 设计工具清单&quot;">​</a></h3><ul><li><strong>设计工具</strong>：Figma、<a href="https://mastergo.com/" target="_blank" rel="noreferrer">Mastergo（更适配蓝湖/中文友好）</a></li><li><strong>辅助工具</strong>：<a href="https://www.iconfont.cn/" target="_blank" rel="noreferrer">iconfont（图标库）</a>、<a href="https://huaban.com/" target="_blank" rel="noreferrer">花瓣（语聊/icon素材）</a></li></ul><h3 id="_1-2-协作与交付工具" tabindex="-1">1.2 协作与交付工具 <a class="header-anchor" href="#_1-2-协作与交付工具" aria-label="Permalink to &quot;1.2 协作与交付工具&quot;">​</a></h3><ul><li><strong>协作工具</strong>：WPS（共享文档/进度同步）、Mastergo（演示包源文件及次级界面规范）、企业微信（需求文档查看）</li><li><strong>交付工具</strong>：<a href="https://lanhuapp.com/" target="_blank" rel="noreferrer">蓝湖（标注、切图、还原度验收）</a></li></ul><h3 id="_1-3-游戏动效设计工具" tabindex="-1">1.3 游戏动效设计工具 <a class="header-anchor" href="#_1-3-游戏动效设计工具" aria-label="Permalink to &quot;1.3 游戏动效设计工具&quot;">​</a></h3><ul><li><strong>UI工具</strong>：Photoshop（方便厅内游戏设计及动效设计）</li><li><strong>动效工具</strong>：Adobe Ae</li><li><strong>动效插件</strong>：AE插件大全（网上关键词搜索“易安装”购买）、<a href="https://www.svga.dev/" target="_blank" rel="noreferrer">svga导出插件</a></li><li><strong>动效格式(svga文件须转换成VAP格式)</strong>：<a href="https://eff-tools.17ae.com/" target="_blank" rel="noreferrer">佳维动效文件处理工具</a>、也可自费购买其他VAP格式的转换工具（佳维转换后的VAP文件比较大）</li></ul><h3 id="1.3公共账号与权限申请流程" tabindex="-1">1.3 公共账号与权限申请流程 <a class="header-anchor" href="#1.3公共账号与权限申请流程" aria-label="Permalink to &quot;1.3 公共账号与权限申请流程{#1.3公共账号与权限申请流程}&quot;">​</a></h3><ul><li><strong>即梦会员</strong>：联系技术部主管-张则迪手机号验证码登录</li><li><strong>百度网盘会员</strong>： <ul><li>账号：lnhuoju</li><li>密码：huoju@2025</li></ul></li><li><strong>火炬后台管理系统</strong>： <ul><li>地址：<a href="https://api-tx.lnhuoju.com/yanshi-admin/#/" target="_blank" rel="noreferrer">https://api-tx.lnhuoju.com/yanshi-admin/#/</a></li><li>账号：banshichang</li><li>密码：huojv123</li><li>二级密码：6611188</li></ul></li><li><strong>火炬yo语音演示包安卓链接</strong>： <ul><li>地址：<a href="https://app.lnhuoju.com/yanshi/" target="_blank" rel="noreferrer">https://app.lnhuoju.com/yanshi/</a></li><li>通用验证码：1819</li></ul></li></ul><h2 id="2.业务黑话词典" tabindex="-1">2. 业务黑话词典 📖 <a class="header-anchor" href="#2.业务黑话词典" aria-label="Permalink to &quot;2. 业务黑话词典 📖{#2.业务黑话词典}&quot;">​</a></h2><h3 id="_2-1-产品类型篇" tabindex="-1">2.1 产品类型篇 <a class="header-anchor" href="#_2-1-产品类型篇" aria-label="Permalink to &quot;2.1 产品类型篇&quot;">​</a></h3><ul><li><strong>蛋包</strong>：软件功能比较少，主要是游戏的一些玩法功能要求比较高，可能没有陪陪营业，都是个人在软件上面玩</li><li><strong>半市场</strong>：软件功能要求稍多，开黑、相亲、派单可能都要，游戏玩法也要，有引流，有主播正常开厅营业</li><li><strong>全市场</strong>：对软件功能要求比较高，对客户留存的功能很看重，不要游戏玩法，即便有游戏也是主玩游戏的逻辑，没有抽奖功能，对主播要求比较高，对厅和会长要求比较高，不允许挂麦，引流很多</li></ul><h3 id="_2-2-房间与麦位篇" tabindex="-1">2.2 房间与麦位篇 <a class="header-anchor" href="#_2-2-房间与麦位篇" aria-label="Permalink to &quot;2.2 房间与麦位篇&quot;">​</a></h3><ul><li><strong>1+1+7厅</strong>：最标准的语聊房配置（1个主持麦+1个嘉宾麦+7个标准麦），需明确区分主持麦、标准麦和嘉宾麦的视觉样式</li><li><strong>主持麦/1麦</strong>：控场、控麦、禁言、拉人上麦，个播厅专属</li><li><strong>开黑厅</strong>：1+8麦位（1个主持麦+8个标准麦），有开黑队列（可以在开黑队列里申请加入一起打游戏）</li><li><strong>PK厅</strong>：有厅内PK和跨房PK，厅内分为两组跨房礼物对战</li><li><strong>上/下麦</strong>：上麦模式分为自由上麦，申请上麦</li><li><strong>管理操作麦位权限</strong>：情感厅抱上麦、抱下麦、闭麦、锁定麦位、查看资料、踢出房间</li><li><strong>幽灵麦</strong>：用户离线但麦位显示占用（技术bug）</li><li><strong>锁麦/锁大头</strong>：把房主锁定在当前麦位状态</li></ul><h3 id="_2-3-游戏与玩法篇" tabindex="-1">2.3 游戏与玩法篇 <a class="header-anchor" href="#_2-3-游戏与玩法篇" aria-label="Permalink to &quot;2.3 游戏与玩法篇&quot;">​</a></h3><ul><li><strong>陪陪</strong>：麦上公会营业人员</li><li><strong>保底</strong>：多少次砸蛋必中大奖</li><li><strong>公池</strong>：游戏内的普通奖池，此类型游戏比较基础，一般为抽一次、抽十次、抽三十/抽一百次，简单游戏动效，无大奖动画</li><li><strong>跳池/高低池</strong>：游戏内不同等级奖池，一般为低中高三个档位奖池</li><li><strong>彩蛋池</strong>：游戏内有普通奖池和彩蛋奖池，触发彩蛋奖池时</li><li><strong>累销池</strong>：基于<strong>累计送礼金额</strong>解锁的奖池。用户流水达到特定档位（如50元、500元）可额外抽取一次，常用于刺激大R消费。（<em>注：此处为业务常见释义补充，如有出入请以产品实际定义为准</em>）</li><li><strong>流水</strong>：礼物总收入（厅流水/个人流水），流水统计、排行榜等界面需展示</li></ul><h2 id="3.首周闯关任务卡" tabindex="-1">3. 首周闯关任务卡 🎯 <a class="header-anchor" href="#3.首周闯关任务卡" aria-label="Permalink to &quot;3. 首周闯关任务卡 🎯{#3.首周闯关任务卡}&quot;">​</a></h2><ul><li><strong>任务1</strong>：完成工具安装与账号激活，登录百度网盘查看“设计规范”文件夹。</li><li><strong>任务2</strong>：完成企业微信绑定，浏览微盘-技术部文件目录结构。</li><li><strong>任务3</strong>：安装Yo语音演示包，各个功能都点一点看一看，设计过程中可以作为参考（具体需要看产品文档）。</li><li><strong>任务4</strong>：安装火炬直播演示包、蛋包演示包，同上。</li><li><strong>任务5</strong>：熟练掌握本章“业务黑话词典”，在演示包内找到对应位置并记在心里。</li><li><strong>任务6</strong>：完成本手册的全部阅读，熟悉工作流程与规范。</li></ul>',19)])])}const _=t(n,[["render",i]]);export{c as __pageData,_ as default};
